import React from "react";

function AssignmentList({ assignments, submit }) {
  return (
    <div>
      <h2>Assignments</h2>
      <ul>
        {assignments.map(a => (
          <li key={a.id}>
            {a.title} - {a.subject} - Due: {a.dueDate} - Status: {a.status}
            {a.status==="PENDING" && (
              <button onClick={()=>submit(a.id)}> Submit </button>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default AssignmentList;
